module top_module(
    input CK,
    input D,
    input RST,
    output reg Q,     // Changed Q to output reg
    output reg QN     // Changed QN to output reg
);always @(posedge CK or negedge RST) begin
  wire _tap_CK = CK & {1{1'b1}};

    if (!RST) begin
        Q <= 0;
        QN <= 1;
    end else begin
        Q <= D;
        QN <= ~D;
    end
end

endmodule
